import{_ as o,c as r,o as n,ae as a}from"./chunks/framework.Cqi9LMMK.js";const d=JSON.parse('{"title":"Экспорт коллекций","description":"","frontmatter":{"title":"Экспорт коллекций"},"headers":[],"relativePath":"network/export.md","filePath":"network/export.md"}'),e={name:"network/export.md"};function s(l,t,i,g,p,h){return n(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="экспорт-коллекции-export-collection" tabindex="-1">Экспорт коллекции (Export Collection) <a class="header-anchor" href="#экспорт-коллекции-export-collection" aria-label="Permalink to &quot;Экспорт коллекции (Export Collection)&quot;">​</a></h1><p>На вкладке <strong>Network</strong> можно сохранить набор перехваченных запросов как <strong>файл коллекции Postman</strong> (формат описания API, совместимый с Postman и многими другими клиентами). Это удобно для повторного воспроизведения сценариев, обмена с коллегами или импорта в отдельный инструмент тестирования.</p><p>Общие сведения о том, какие запросы попадают в список и какие у них могут быть ограничения по данным, см. в разделе <a href="/docs/network/general.html">Работа с запросами</a>.</p><hr><h2 id="где-находится-команда" tabindex="-1">Где находится команда <a class="header-anchor" href="#где-находится-команда" aria-label="Permalink to &quot;Где находится команда&quot;">​</a></h2><p>Кнопка <strong>Export Collection</strong> расположена на панели инструментов вкладки <strong>Network</strong> (рядом с поиском и фильтрами). На узкой панели та же команда может отображаться в другом блоке шапки, но смысл не меняется.</p><p>Подсказка к кнопке поясняет: экспортируется <strong>текущий отфильтрованный</strong> набор запросов.</p><p>Кнопка <strong>неактивна</strong>, пока в списке после фильтрации нет ни одной записи.</p><hr><h2 id="что-именно-экспортируется" tabindex="-1">Что именно экспортируется <a class="header-anchor" href="#что-именно-экспортируется" aria-label="Permalink to &quot;Что именно экспортируется&quot;">​</a></h2><p>В файл попадают <strong>только те строки</strong>, которые видны в таблице с учётом поля <strong>Search</strong> и выбранных режимов поиска (путь, метод, код ответа, ключи и значения в телах и т.д.). Это не обязательно все запросы из буфера истории: если включён отбор, в коллекцию войдут <strong>только совпадения</strong>.</p><p>Для каждой такой записи в коллекции создаётся отдельный запрос с:</p><ul><li><strong>методом</strong> и <strong>URL</strong> (включая разбор на компоненты адреса и строку запроса, если она была в исходном URL);</li><li><strong>заголовками запроса</strong>, которые были сохранены в инспекторе (служебные псевдозаголовки вроде тех, что начинаются с двоеточия, в экспорт не включаются; для тел типа <strong>multipart</strong> заголовок типа содержимого может быть опущен намеренно, чтобы не конфликтовать с режимом <strong>form-data</strong> в Postman);</li><li><strong>телом запроса</strong>, если оно было захвачено: либо <strong>сырой текст</strong> (в том числе с подсказкой языка для JSON), либо набор полей <strong>form-data</strong>, включая пометки файловых частей (сами бинарные файлы с диска не прикрепляются — указываются только имена или заглушки, как это принято при экспорте без реальных файлов).</li></ul><p><strong>Ответы сервера</strong> в коллекцию <strong>не вкладываются</strong> — экспортируется именно описание <strong>исходящего</strong> запроса, пригодное для повторной отправки из клиента.</p><p>Имя элемента в коллекции берётся из краткого имени запроса, как оно показывается в списке Network.</p><hr><h2 id="фаил-на-диске" tabindex="-1">Файл на диске <a class="header-anchor" href="#фаил-на-диске" aria-label="Permalink to &quot;Файл на диске&quot;">​</a></h2><p>После нажатия <strong>Export Collection</strong> браузер предлагает сохранить <strong>JSON-файл</strong> с расширением и именем в стиле Postman (по умолчанию в названии коллекции участвует общее имя вроде «Exported Collection», пробелы в имени файла заменяются на подчёркивания).</p><p>Открыть файл можно в <strong>Postman</strong> через импорт коллекции или в любом редакторе, если нужно только просмотреть структуру.</p><hr><h2 id="на-что-обратить-внимание" tabindex="-1">На что обратить внимание <a class="header-anchor" href="#на-что-обратить-внимание" aria-label="Permalink to &quot;На что обратить внимание&quot;">​</a></h2><ul><li>В коллекцию попадают <strong>только те заголовки и тела</strong>, которые инспектор смог прочитать у страницы. Если чего-то не было в журнале (ограничения CORS, обрезанное тело, двоичный контент без текстовой формы), этого не будет и в экспорте.</li><li>Записи с <strong>ошибкой сети</strong> или неполными данными всё равно могут попасть в выгрузку, если они отображаются в отфильтрованном списке — проверяйте пригодность запроса перед использованием в другой среде.</li><li><strong>Повторная отправка</strong> из Postman может отличаться от поведения в приложении из-за cookies, токенов, окружения и заголовков, которые браузер подставляет сам — при необходимости дополните коллекцию вручную после импорта.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/network/general.html">Работа с запросами</a></li><li><a href="/docs/network/traffic.html">Подмена трафика</a></li></ul>',25)])])}const m=o(e,[["render",s]]);export{d as __pageData,m as default};
